import javax.inject._
import play.api.mvc._
import play.api.libs.json._
import scala.concurrent.ExecutionContext
import slick.jdbc.PostgresProfile.api._
import scala.concurrent.Future

case class Product(id: Int, name: String, description: String, price: Double, category: String)

@Singleton
class ProductSearchController @Inject()(val controllerComponents: ControllerComponents)(implicit ec: ExecutionContext) extends BaseController {
  
  def search() = Action.async { implicit request =>
    val name = request.queryString.get("name").flatMap(_.headOption)
    val category = request.queryString.get("category").flatMap(_.headOption)
    val minPrice = request.queryString.get("minPrice").flatMap(_.headOption).map(_.toDouble)
    val maxPrice = request.queryString.get("maxPrice").flatMap(_.headOption).map(_.toDouble)
    
    val whereClauses = scala.collection.mutable.ListBuffer.empty[SqlNode]
    
    name.foreach { n =>
      whereClauses += sql"LOWER(name) LIKE LOWER(${n.toLowerCase} || '%')"
    }
    
    category.foreach { c =>
      whereClauses += sql"category = ${c}"
    }
    
    minPrice.foreach { p =>
      whereClauses += sql"price >= ${p}"
    }
    
    maxPrice.foreach { p =>
      whereClauses += sql"price <= ${p}"
    }
    
    val sqlFragment = if (whereClauses.nonEmpty) {
      sql"WHERE " ++ whereClauses.reduce(_ ++ sql" AND " ++ _)
    } else {
      sql""
    }
    
    val query = sql"SELECT * FROM products " ++ sqlFragment
    
    val products = query.as[Product]
    
    Future.successful(Ok(Json.toJson(products)))
  }
